import type { Result, Router } from '../../router'
import { MESSAGE_MATCHER_IS_ALREADY_BUILT, UnsupportedPathError } from '../../router'

export class SmartRouter<T> implements Router<T> {
  name: string = 'SmartRouter'
  #routers: Router<T>[] = []
  #routes?: [string, string, T][] = []

  constructor(init: { routers: Router<T>[] }) {
    this.#routers = init.routers
  }

  add(method: string, path: string, handler: T) {
    if (!this.#routes) {
      throw new Error(MESSAGE_MATCHER_IS_ALREADY_BUILT)
    }

    this.#routes.push([method, path, handler])
  }

  match(method: string, path: string): Result<T> {
    if (!this.#routes) {
      throw new Error('Fatal error')
    }

    const routers = this.#routers
    const routes = this.#routes

    const len = routers.length
    let i = 0
    let res
    for (; i < len; i++) {
      const router = routers[i]
      try {
        for (let i = 0, len = routes.length; i < len; i++) {
          router.add(...routes[i])
        }
        res = router.match(method, path)
      } catch (e) {
        if (e instanceof UnsupportedPathError) {
          continue
        }
        throw e
      }

      this.match = router.match.bind(router)
      this.#routers = [router]
      this.#routes = undefined
      break
    }

    if (i === len) {
      // not found
      throw new Error('Fatal error')
    }

    // e.g. "SmartRouter + RegExpRouter"
    this.name = `SmartRouter + ${this.activeRouter.name}`

    return res as Result<T>
  }

  get activeRouter(): Router<T> {
    if (this.#routes || this.#routers.length !== 1) {
      throw new Error('No active router has been determined yet.')
    }

    return this.#routers[0]
  }
}

export const timing = (config?: TimingOptions): MiddlewareHandler => {
  const options: TimingOptions = {
    total: true,
    enabled: true,
    totalDescription: 'Total Response Time',
    autoEnd: true,
    crossOrigin: false,
    ...config,
  }
  return async function timing(c, next) {
    const headers: string[] = []
    const timers = new Map<string, Timer>()

    if (c.get('metric')) {
      return await next()
    }

    c.set('metric', { headers, timers })

    if (options.total) {
      startTime(c, 'total', options.totalDescription)
    }
    await next()

    if (options.total) {
      endTime(c, 'total')
    }

    if (options.autoEnd) {
      timers.forEach((_, key) => {
        endTime(c, key)
      })
    }

    const enabled = typeof options.enabled === 'function' ? options.enabled(c) : options.enabled

    if (enabled) {
      c.res.headers.append('Server-Timing', headers.join(','))

      const crossOrigin =
        typeof options.crossOrigin === 'function' ? options.crossOrigin(c) : options.crossOrigin

      if (crossOrigin) {
        c.res.headers.append(
          'Timing-Allow-Origin',
          typeof crossOrigin === 'string' ? crossOrigin : '*'
        )
      }
    }
  }
}

export const prometheus = (
  options?: PrometheusOptions
): {
  printMetrics: (
    c: Context
  ) => Promise<Response & TypedResponse<string, ContentfulStatusCode, 'text'>>
  registerMetrics: MiddlewareHandler
} => {
  const {
    registry = new Registry(),
    collectDefaultMetrics = false,
    prefix = '',
    metricOptions,
  } = options ?? {}

  if (collectDefaultMetrics) {
    promCollectDefaultMetrics({
      prefix,
      register: registry,
      ...(typeof collectDefaultMetrics === 'object' && collectDefaultMetrics),
    })
  }

  const metrics = createStandardMetrics({
    prefix,
    registry,
    customOptions: metricOptions,
  })

  return {
    printMetrics: async (c: Context) => c.text(await registry.metrics()),
    registerMetrics: createMiddleware(async (c, next) => {
      const timer = metrics.requestDuration?.startTimer()

      try {
        await next()
      } finally {
        const commonLabels = {
          method: c.req.method,
          route: c.req.routePath,
          status: c.res.status.toString(),
          ok: String(c.res.ok),
        }

        timer?.({
          ...commonLabels,
          ...evaluateCustomLabels(metricOptions?.requestDuration?.customLabels, c),
        })

        metrics.requestsTotal?.inc({
          ...commonLabels,
          ...evaluateCustomLabels(metricOptions?.requestsTotal?.customLabels, c),
        })
      }
    }),
  }
}

import { httpInstrumentationMiddleware } from '@hono/otel';
import { OpenAPIHono } from '@hono/zod-openapi';
import { compress } from 'hono/compress';
import { cors } from 'hono/cors';
import { csrf } from 'hono/csrf';
import { secureHeaders } from 'hono/secure-headers';
import { appConfig } from 'shared';
import type { Env } from '#/core/context';
import { dynamicBodyLimit } from '#/middlewares/body-limit';
import { loggerMiddleware } from '#/middlewares/logger';

const app = new OpenAPIHono<Env>();

// Secure headers
app.use(
  '*',
  secureHeaders({
    referrerPolicy: 'strict-origin-when-cross-origin',
    strictTransportSecurity: 'max-age=31536000; includeSubDomains; preload',
    permissionsPolicy: { camera: [], microphone: [], geolocation: [] },
  }),
);

// OpenTelemetry HTTP instrumentation (route-aware spans)
app.use(
  '*',
  httpInstrumentationMiddleware({
    serviceName: appConfig.name,
    serviceVersion: '1.0',
  }),
);

// Logger (pino)
app.use('*', loggerMiddleware);

const corsOptions: Parameters<typeof cors>[0] = {
  origin: appConfig.frontendUrl,
  credentials: true,
  allowMethods: ['GET', 'HEAD', 'PUT', 'POST', 'DELETE'],
  allowHeaders: ['content-type', 'x-cache-token', 'traceparent', 'tracestate'],
  maxAge: 7200,
};

// CORS
app.use('*', cors(corsOptions));

// CSRF protection
app.use('*', csrf({ origin: appConfig.frontendUrl }));

// Body limit
app.use('*', dynamicBodyLimit);

// Compress with gzip Apply gzip compression only to GET requests
app.use('*', (c, next) => {
  if (c.req.method === 'GET') {
    return compress()(c, next);
  }
  return next();
});

export default app;

import type { MiddlewareHandler } from 'hono'
import { createMiddleware } from 'hono/factory'
import type { transform, initialize } from './types.esbuild'

export type EsbuildLike = {
  transform: typeof transform
  initialize: typeof initialize
}

export type TransformOptions = Partial<Parameters<typeof transform>[1]>

export type EsbuildTranspilerOptions = {
  extensions?: string[]
  cache?: boolean
  esbuild?: EsbuildLike
  contentType?: string
  transformOptions?: TransformOptions
}

export const esbuildTranspiler = (options?: EsbuildTranspilerOptions): MiddlewareHandler => {
  const esbuild: EsbuildLike | undefined = options?.esbuild

  return createMiddleware(async (c, next) => {
    await next()
    if (esbuild) {
      const url = new URL(c.req.url)
      const extensions = options?.extensions ?? ['.ts', '.tsx']

      if (extensions.every((ext) => !url.pathname.endsWith(ext))) {
        return
      }

      const script = await c.res.text()
      const transformOptions: TransformOptions = options?.transformOptions ?? {}

      try {
        const { code } = await esbuild.transform(script, {
          loader: 'tsx',
          ...transformOptions,
        })
        c.res = c.body(code)
        c.res.headers.set('content-type', options?.contentType ?? 'text/javascript')
        c.res.headers.delete('content-length')
      } catch (ex) {
        console.warn('Error transpiling ' + url.pathname + ': ' + ex)
        c.res = new Response(script, {
          status: 500,
          headers: { 'content-type': options?.contentType ?? 'text/javascript' },
        })
      }
    }
  })
}

import {
  InvalidRequestError,
  OAuthError,
  ServerError,
} from '@modelcontextprotocol/sdk/server/auth/errors.js'
import type { OAuthServerProvider } from '@modelcontextprotocol/sdk/server/auth/provider.js'
import { OAuthTokenRevocationRequestSchema } from '@modelcontextprotocol/sdk/shared/auth.js'
import type { MiddlewareHandler } from 'hono'
import type { ClientAuthenticationEnv } from '../middleware/client-auth'

export function revokeHandler(
  provider: OAuthServerProvider
): MiddlewareHandler<ClientAuthenticationEnv> {
  if (!provider.revokeToken) {
    throw new Error('Auth provider does not support revoking tokens')
  }

  return async (c) => {
    c.header('Cache-Control', 'no-store')

    try {
      const parseResult = OAuthTokenRevocationRequestSchema.safeParse(await c.req.json())
      if (!parseResult.success) {
        throw new InvalidRequestError(parseResult.error.message)
      }

      const client = c.get('client')
      if (!client) {
        // This should never happen
        throw new ServerError('Internal Server Error')
      }

      await provider.revokeToken!(client, parseResult.data)
      return c.json({})
    } catch (error) {
      if (error instanceof OAuthError) {
        const status = error instanceof ServerError ? 500 : 400
        return c.json(error.toResponseObject(), status)
      } else {
        const serverError = new ServerError('Internal Server Error')
        return c.json(serverError.toResponseObject(), 500)
      }
    }
  }
}

import { boolean, pgTable, timestamp, uuid, varchar } from 'drizzle-orm/pg-core'
import { createInsertSchema, createSelectSchema, createUpdateSchema } from 'drizzle-zod'

export const tasks = pgTable('tasks', {
  id: uuid()
    .primaryKey()
    .defaultRandom(),
  done: boolean()
    .default(false)
    .notNull(),
  name: varchar({ length: 255 })
    .notNull(),
  createdAt: timestamp({ mode: 'date' })
    .defaultNow()
    .notNull(),
