    name: schema => schema.min(1).max(255).describe('The name of the task.'),
    done: schema => schema.describe('Whether the task is completed.').default(false),
  },
).required({
  done: true,
}).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
})

export const taskPatchSchema = createUpdateSchema(
