  updatedAt: true,
})

app.post("/", async (c) => {
  // Getting the raw data
  let raw = await (c.req.header("Content-Type") === "application/json"
    ? c.req.json()
    : c.req.formData());

  if (!raw)
    throw new HTTPException(404, {
      message: "Request body is missing or empty",
    });

  for (const hook of collection.hooks.beforeValidate ?? []) {
    const res = await hook({
      context: c,
      data: raw,
    });
    if (res !== undefined) raw = res;
  }

  // Parsing the value
  const parsedData = await collectionInsertSchema.safeParseAsync(raw);

  if (!parsedData.success) {
    return c.json(parsedData, 400);
  }

  let data = parsedData.data;

  for (const hook of collection.hooks.beforeChange ?? []) {
    const res = await hook({
      context: c,
      data,
    });

    // @ts-expect-error
    if (res !== undefined) data = res;
  }

  // Saving the record
  const createdDocQuery = db
    .insert(collection.schema)
    .values(data)
    .$dynamic();

  if (
    "$returningId" in createdDocQuery &&
    typeof createdDocQuery.$returningId === "function"
  ) {
    createdDocQuery.$returningId?.();
  } else {
    createdDocQuery.returning();
  }

  let createdDoc: any = await createdDocQuery.execute();

  for (const hook of collection.hooks.afterChange ?? []) {
    const res = await hook({
      context: c,
      doc: createdDoc,
      previousDoc: data,
    });

    if (res !== undefined) createdDoc = res;
  }

  // Returning the response
  // @ts-ignore
  return c.json(createdDoc);
});

import { and, eq, or } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db, { schema } from "../database";

export async function validateWorkspaceAccess(
  userId: string,
  workspaceId: string,
  apiKeyId?: string,
): Promise<void> {
  if (apiKeyId) {
    const apiKey = await db
      .select()
      .from(schema.apikeyTable)
      .where(
        and(
          eq(schema.apikeyTable.id, apiKeyId),
          or(
            eq(schema.apikeyTable.referenceId, userId),
            eq(schema.apikeyTable.userId, userId),
          ),
          eq(schema.apikeyTable.enabled, true),
        ),
      )
      .limit(1);

    if (apiKey.length === 0) {
      throw new HTTPException(403, {
        message: "Invalid API key for this workspace",
      });
    }
  }

  const [user] = await db
    .select({ role: schema.userTable.role })
    .from(schema.userTable)
    .where(eq(schema.userTable.id, userId))
    .limit(1);

  if (user?.role === "admin") {
    return;
  }

  const membership = await db
    .select()
    .from(schema.workspaceUserTable)
    .where(
      and(
        eq(schema.workspaceUserTable.userId, userId),
        eq(schema.workspaceUserTable.workspaceId, workspaceId),
      ),
    )
    .limit(1);

  if (membership.length === 0) {
    throw new HTTPException(403, {
      message: "You don't have access to this workspace",
    });
  }
}

export const html = (
  strings: TemplateStringsArray,
  ...values: unknown[]
): HtmlEscapedString | Promise<HtmlEscapedString> => {
  const buffer: StringBufferWithCallbacks = [''] as StringBufferWithCallbacks

  for (let i = 0, len = strings.length - 1; i < len; i++) {
    buffer[0] += strings[i]

    const children = Array.isArray(values[i])
      ? (values[i] as Array<unknown>).flat(Infinity)
      : [values[i]]
    for (let i = 0, len = children.length; i < len; i++) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const child = children[i] as any
      if (typeof child === 'string') {
        escapeToBuffer(child, buffer)
      } else if (typeof child === 'number') {
        ;(buffer[0] as string) += child
      } else if (typeof child === 'boolean' || child === null || child === undefined) {
        continue
      } else if (typeof child === 'object' && (child as HtmlEscaped).isEscaped) {
        if ((child as HtmlEscapedString).callbacks) {
          buffer.unshift('', child)
        } else {
          const tmp = child.toString()
          if (tmp instanceof Promise) {
            buffer.unshift('', tmp)
          } else {
            buffer[0] += tmp
          }
        }
      } else if (child instanceof Promise) {
        buffer.unshift('', child)
      } else {
        escapeToBuffer(child.toString(), buffer)
      }
    }
  }
  buffer[0] += strings.at(-1) as string

  return buffer.length === 1
    ? 'callbacks' in buffer
      ? raw(resolveCallbackSync(raw(buffer[0], buffer.callbacks)))
      : raw(buffer[0])
    : stringBufferToString(buffer, buffer.callbacks)
}

import { createMiddleware } from 'hono/factory';
import type { AppBindings } from '@/lib/context';

export const serviceFetcherMiddleware = createMiddleware<AppBindings>(
  async (c, next) => {
    // Auth worker binding is optional in some deployments (e.g. AUTH_MODE=jwt/none),
    // so we must be defensive at runtime.
    //
    // We intentionally avoid relying on generated binding types here because
    // template/CLI deployments may omit the auth worker entirely.
    const authWorker = (
      c.env as unknown as { AUTH_WORKER?: { fetch: typeof fetch } }
    ).AUTH_WORKER;

    const serviceFetcher =
      typeof authWorker?.fetch === 'function'
        ? authWorker.fetch.bind(authWorker)
        : fetch;
    c.set('serviceFetcher', serviceFetcher);

    const authClientServiceFetcher = async (
      input: RequestInfo | URL,
      init?: RequestInit,
    ) => {
      const headers = new Headers(init?.headers);

      // Forward session cookies
      const cookieHeader = c.req.header('cookie');
      if (cookieHeader) {
        headers.set('cookie', cookieHeader);
      }

      return serviceFetcher(input, {
        ...init,
        headers,
      });
    };

    c.set('customFetcher', authClientServiceFetcher);

    return next();
  },
);

import type { ContextEntityType } from 'shared';
import type { AuthContext } from '#/core/context';
import { invalidateCache } from '#/middlewares/guard/invalidate-cache';
import { deleteMembershipsByIds, findMembershipsByUserIdsAndContext } from '#/modules/memberships/memberships-queries';
import { getValidContextEntity } from '#/permissions/get-context-entity';
import { logEvent } from '#/utils/logger';

interface DeleteMembershipsInput {
  ids: string[];
  entityId: string;
  entityType: ContextEntityType;
}

export async function deleteMembershipsOp(ctx: AuthContext, input: DeleteMembershipsInput) {
  const { ids, entityId, entityType } = input;

  const { entity } = await getValidContextEntity(ctx, entityId, entityType, 'delete');

  const membershipIds = Array.isArray(ids) ? ids : [ids];

  const targets = await findMembershipsByUserIdsAndContext(ctx, {
    userIds: membershipIds,
    contextId: entity.id,
  });

  const rejectedIds: string[] = [];

  for (const id of membershipIds) {
    if (!targets.some((target) => target.userId === id)) rejectedIds.push(id);
  }

  if (targets.length === 0) return { data: [] as never[], rejectedIds };

  await deleteMembershipsByIds(ctx, {
    ids: targets.map((target) => target.id),
  });

  for (const target of targets) invalidateCache.user(target.userId);

  logEvent(ctx, 'info', 'Memberships deleted', { count: targets.length, ids: targets.map((t) => t.userId) });

  return { data: [] as never[], rejectedIds };
}

import type { AuthContext } from '#/core/context';
import type { tenantsTable } from '#/db/schema/tenants';
import { invalidateCache } from '#/middlewares/guard/invalidate-cache';
import { createTenantForUser } from '#/modules/tenants/tenant-service';
import { countDomainsByTenant, updateTenant } from '#/modules/tenants/tenants-queries';

interface CreateTenantInput {
  name: string;
  status?: string;
}

export async function createTenantOp(ctx: AuthContext, input: CreateTenantInput) {
  const db = ctx.var.db;
  const user = ctx.var.user;
  const { name, status } = input;

  const tenant = await createTenantForUser(
    db,
    {
      name,
      createdBy: user.id,
      userEmail: user.email,
    },
    ctx,
  );

  // Apply status override if provided (createTenantForUser defaults to 'active')
  if (status && status !== 'active') {
    const updated = await updateTenant(ctx, {
      targetTenantId: tenant.id,
      values: { status: status as typeof tenantsTable.$inferInsert.status },
    });
    invalidateCache.tenant(tenant.id);
    const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
    return { ...updated, domainsCount };
  }

  const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
  return { ...tenant, domainsCount };
}

