import { AppError } from '#/core/error';
import { tenantsTable } from '#/db/schema/tenants';
import { createTenantForUser } from '#/modules/tenants/tenant-service';
import { countDomainsByTenant } from '#/modules/tenants/tenants-queries';

interface SelfCreateTenantInput {
  name: string;
}

export async function selfCreateTenantOp(ctx: AuthContext, input: SelfCreateTenantInput) {
  const db = ctx.var.db;
  const user = ctx.var.user;
  const memberships = ctx.var.memberships;

  // Block if user already has memberships (already in a tenant with orgs)
  if (memberships.length > 0) {
    throw new AppError(409, 'restrict_by_app', 'warn', {
      message: 'User already has tenant memberships',
    });
  }

  // If user already created a tenant (e.g. previous attempt where org creation failed), return it
  const [existingTenant] = await db.select().from(tenantsTable).where(eq(tenantsTable.createdBy, user.id)).limit(1);

  if (existingTenant) {
    const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: existingTenant.id });
    return { ...existingTenant, domainsCount };
  }

  const tenant = await createTenantForUser(
    db,
    {
      name: input.name,
      createdBy: user.id,
      userEmail: user.email,
    },
    ctx,
  );

  const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
  return { ...tenant, domainsCount };
}

import { eq, sql } from 'drizzle-orm';
import type { EntityType } from 'shared';
import { baseDb } from '#/db/db';
import { membershipsTable } from '#/db/schema/memberships';
import { resolveEntity } from '#/modules/entities/entities-queries';
import { checkPermission } from '#/permissions';
import type { SubjectForPermission } from '#/permissions/permission-manager/types';

export async function verifyEntityOp(params: {
  entityType: string;
  entityId: string;
  tenantId: string;
  userId: string;
}) {
  const { entityType, entityId, tenantId, userId } = params;

  // Resolve entity + load user memberships in a single RLS-scoped transaction
  const result = await baseDb.transaction(async (tx) => {
    await tx.execute(sql`SET TRANSACTION READ ONLY`);
    await tx.execute(sql`SELECT set_config('app.tenant_id', ${tenantId}, true)`);

    const [entity, memberships] = await Promise.all([
      resolveEntity({ var: { db: tx } }, entityType as EntityType, entityId),
      tx.select().from(membershipsTable).where(eq(membershipsTable.userId, userId)),
    ]);

    return { entity, memberships };
  });

  if (!result.entity) return { allowed: false };

  // Defense-in-depth: verify tenant match even if RLS is not enforced (e.g. superuser connection)
  if ('tenantId' in result.entity && result.entity.tenantId !== tenantId) {
    return { allowed: false };
  }

  // Check actual update permission — this evaluates the full ancestor chain (project → organization)
  const subject = result.entity as SubjectForPermission;
  const { isAllowed } = checkPermission(result.memberships, 'update', subject);

  return { allowed: isAllowed };
}

