        chunks.push(chunk)
        callback()
      },
    })
    // @ts-expect-error chunks property for testing
    mockWritableStream.chunks = chunks
    await handlerFunc(event, mockWritableStream, context)
    mockWritableStream.end()
    return mockWritableStream
  }
}

